query associatedTargets($efoId: String!) {
  disease(efoId: $efoId) {
    id
    name
    associatedTargets {
      count
      rows {
        target {
          id
          approvedSymbol
        }
        score
      }
    }
  }
}

query associatedDiseases($ensemblId: String!) {
  target(ensemblId: $ensemblId) {
    id
    approvedSymbol
    associatedDiseases {
      count
      rows {
        disease {
          id
          name
        }
        datasourceScores {
          id
          score
        }
      }
    }
  }
}

query targetDiseaseEvidence($efoId: String!, $ensemblId: String!) {
  disease(efoId: $efoId) {
    id
    name
    evidences(datasourceIds: ["intogen"], ensemblIds: [$ensemblId]) {
      count
      rows {
        disease {
          id
          name
        }
        diseaseFromSource
        target {
          id
          approvedSymbol
        }
        mutatedSamples {
          functionalConsequence {
            id
            label
          }
          numberSamplesTested
          numberMutatedSamples
        }
        resourceScore
        significantDriverMethods
        cohortId
        cohortShortName
        cohortDescription
      }
    }
  }
}

query getEvidenceByDatasource($efoId: String!, $ensemblId: String!, $datasourceIds: [String!], $size: Int) {
  disease(efoId: $efoId) {
    id
    name
    evidences(datasourceIds: $datasourceIds, ensemblIds: [$ensemblId], size: $size) {
      count
      rows {
        datasourceId
        datatypeId
        disease {
          id
          name
        }
        diseaseFromSource
        target {
          id
          approvedSymbol
        }
        score
        resourceScore
        literature
        urls {
          url
          niceName
        }
      }
    }
  }
}

query drugWarnings($chemblId: String!) {
  drug(chemblId: $chemblId) {
    id
    name
    drugWarnings {
      warningType
      description
      country
      year
      toxicityClass
      chemblIds
   efoIdForWarningClass
    references {
