}

query diseaseSimilarEntities($efoId: String!, $threshold: Float!, $size: Int!) {
  disease(efoId: $efoId) {
    id
    name
    similarEntities(threshold: $threshold, size: $size) {
      id
      category
      score
      object {
        ... on Disease {
          id
          name
        }
        ... on Target {
          id
          approvedSymbol
        }
        ... on Drug {
          id
          name
        }
      }
    }
  }
}

